-
-extension OptionGroup {
-  @_disfavoredOverload
-  @available(*, deprecated, renamed: "init(title:visibility:)")
-  public init(
-    visibility _visibility: ArgumentVisibility = .default
-  ) {
-    self.init(title: "", visibility: _visibility)
-  }
-}

